Problèmes identifiés :
1) Aucune validation sur `rating` (devrait être entre 1 et 5).
2) `comment` est obligatoire alors qu'un avis pourrait n'avoir que des étoiles sans texte.
3) Pas de colonnes `createdAt` / `updatedAt` (audit trail).
4) Les relations n'ont pas de clés étrangères explicites ni de cascade définie.

Version corrigée :
```typescript
@Entity()
export class Review {
  @PrimaryGeneratedColumn()
  id: number;

  @Column({ type: 'int' })
  @Min(1)
  @Max(5)
  rating: number;

  @Column({ nullable: true, type: 'text' })
  comment?: string;

  @Column('simple-array', { nullable: true })
  images?: string[];

  @ManyToOne(() => User, (user) => user.reviews, { onDelete: 'CASCADE' })
  @JoinColumn({ name: 'userId' })
  user: User;

  @Column()
  userId: number;

  @ManyToOne(() => Product, (product) => product.reviews, { onDelete: 'CASCADE' })
  @JoinColumn({ name: 'productId' })
  product: Product;

  @Column()
  productId: number;

  @CreateDateColumn()
  createdAt: Date;

  @UpdateDateColumn()
  updatedAt: Date;
}
