async createReview(userId: number, createReviewDto: CreateReviewDto): Promise<Review> {
  const { productId, rating, comment, images } = createReviewDto;

  // 1. Vérifier que l'utilisateur a acheté ce produit
  const hasPurchased = await this.orderRepository
    .createQueryBuilder('order')
    .innerJoin('order.items', 'item')
    .where('order.userId = :userId', { userId })
    .andWhere('item.productId = :productId', { productId })
    .andWhere('order.status IN (:...statuses)', { statuses: ['paid', 'delivered'] })
    .getExists();

  if (!hasPurchased) {
    throw new ForbiddenException(
      `Vous ne pouvez laisser un avis que sur un produit que vous avez acheté.`
    );
  }

  // 2. Vérifier que l'utilisateur n'a pas déjà laissé un avis sur ce produit
  const existingReview = await this.reviewRepository.findOne({
    where: { userId, productId },
  });

  if (existingReview) {
    throw new ConflictException('Vous avez déjà laissé un avis sur ce produit.');
  }

  // 3. Créer l'avis
  const review = this.reviewRepository.create({
    userId,
    productId,
    rating,
    comment,
    images,
  });

  return this.reviewRepository.save(review);
}
