```typescript
// DTO
export class CreateReviewDto {
  @IsNumber()
  @Min(1)
  @Max(5)
  rating: number;

  @IsOptional()
  @IsString()
  @MaxLength(1000)
  comment?: string;

  @IsOptional()
  @ArrayMaxSize(3)
  @IsArray()
  images?: string[]; // URLs après upload
}

// Service
@Injectable()
export class ReviewService {
  constructor(
    @InjectRepository(Review)
    private reviewRepository: Repository<Review>,
    @InjectRepository(Order)
    private orderRepository: Repository<Order>,
    private cloudinaryService: CloudinaryService,
  ) {}

  async createReview(
    userId: number,
    productId: number,
    createReviewDto: CreateReviewDto,
    files: Array<Express.Multer.File>,
  ): Promise<Review> {
    // Vérification d'achat (voir exercice précédent)
    const hasPurchased = await this.verifyPurchase(userId, productId);
    if (!hasPurchased) {
      throw new ForbiddenException('Vous devez avoir acheté ce produit pour laisser un avis.');
    }

    // Upload des images vers Cloudinary
    const imageUrls: string[] = [];
    if (files && files.length > 0) {
      for (const file of files) {
        const result = await this.cloudinaryService.uploadImage(file, 'reviews');
        imageUrls.push(result.secure_url);
      }
    }

    const review = this.reviewRepository.create({
      userId,
      productId,
      rating: createReviewDto.rating,
      comment: createReviewDto.comment,
      images: imageUrls,
    });

    const savedReview = await this.reviewRepository.save(review);

    // Mettre à jour la note moyenne du produit
    await this.updateProductAverageRating(productId);

    return savedReview;
  }

  private async verifyPurchase(userId: number, productId: number): Promise<boolean> {
    const order = await this.orderRepository.findOne({
      where: {
        userId,
        status: In(['paid', 'delivered']),
        items: { productId },
      },
      relations: ['items'],
    });
    return !!order;
  }
}

// Controller
@Controller('reviews')
@UseGuards(JwtAuthGuard)
export class ReviewController {
  constructor(private reviewService: ReviewService) {}

  @Post('product/:productId')
  @UseInterceptors(FileInterceptor('images', { limits: { files: 3 } }))
  async createReview(
    @Param('productId', ParseIntPipe) productId: number,
    @CurrentUser() user: User,
    @Body() createReviewDto: CreateReviewDto,
    @UploadedFiles() files?: Array<Express.Multer.File>,
  ) {
    return this.reviewService.createReview(user.id, productId, createReviewDto, files);
  }
}
